 89	var executorPrompt = prompt.FromMessages(schema.FString,
 90		schema.SystemMessage(`You are a diligent travel booking assistant. Follow the given plan and execute your tasks carefully.
 91	Execute each planning step by using available tools.
 92	For weather queries, use get_weather tool.
 93	For flight bookings, use book_flight tool - this will require user review before confirmation.
 94	For hotel bookings, use book_hotel tool - this will require user review before confirmation.
 95	For attraction research, use search_attractions tool.
 96	Provide detailed results for each task.`),
 97		schema.UserMessage(`## OBJECTIVE
 98	{input}
 99	## Given the following plan:
100	{plan}
101	## COMPLETED STEPS & RESULTS
102	{executed_steps}
103	## Your task is to execute the first step, which is: 
104	{step}`))
105	
106	func formatInput(in []adk.Message) string {
107		return in[0].Content
108	}
109	
110	func formatExecutedSteps(in []planexecute.ExecutedStep) string {
111		var sb strings.Builder
112		for idx, m := range in {
113			_, _ = fmt.Fprintf(&sb, "## %d. Step: %v\n  Result: %v\n\n", idx+1, m.Step, m.Result)
114		}
115		return sb.String()
116	}
