161	func NewTravelPlanningAgent(ctx context.Context) (adk.Agent, error) {
162		planAgent, err := NewPlanner(ctx)
163		if err != nil {
164			return nil, err
165		}
166	
167		executeAgent, err := NewExecutor(ctx)
168		if err != nil {
169			return nil, err
170		}
171	
172		replanAgent, err := NewReplanner(ctx)
173		if err != nil {
174			return nil, err
175		}
176	
177		return planexecute.New(ctx, &planexecute.Config{
178			Planner:       planAgent,
179			Executor:      executeAgent,
180			Replanner:     replanAgent,
181			MaxIterations: 20,
182		})
183	}

