224	func buildProjectManagerSupervisor(ctx context.Context) (adk.Agent, error) {
225		m := newRateLimitedModel()
226	
227		sv, err := adk.NewChatModelAgent(ctx, &adk.ChatModelAgentConfig{
228			Name:        "project_manager",
229			Description: "the supervisor agent responsible for coordinating project management tasks",
230			Instruction: `You are a project manager supervisor managing two agents:
231	
232	- a research_agent: Assign quick research and information gathering tasks to this agent (market research, technology trends, competitor analysis)
233	- a project_execution_agent: Assign complex project execution tasks to this agent (project setup, requirements analysis, design creation, budget allocation, team assignment)
234	
235	INSTRUCTIONS:
236	- Analyze the user's request and delegate to the appropriate agent
237	- For simple research queries, use research_agent
238	- For complex project tasks that require multiple steps (like setting up a new project), use project_execution_agent
239	- The project_execution_agent will create a plan and execute it step by step
240	- Budget allocation requires user approval - the project_execution_agent will handle this
241	- Assign work to one agent at a time, do not call agents in parallel
242	- Do not do any work yourself - always delegate to the appropriate agent
243	- After all tasks are complete, summarize the results for the user`,
244			Model: m,
245			Exit:  &adk.ExitTool{},
246		})
247		if err != nil {
248			return nil, err
249		}
250	
251		researchAgent, err := buildResearchAgent(ctx)
252		if err != nil {
253			return nil, err
254		}
255	
256		projectExecutionAgent, err := buildProjectExecutionAgent(ctx)
257		if err != nil {
258			return nil, err
259		}
260	
261		return supervisor.New(ctx, &supervisor.Config{
262			Supervisor: sv,
263			SubAgents:  []adk.Agent{researchAgent, projectExecutionAgent},
264		})
265	}

