## WriteTodos 工具实现

WriteTodos 工具的核心思想是：**让 Agent 通过工具调用的方式自主管理任务列表**。

### 1. 数据结构定义

```go
// 任务状态
type TaskStatus string

const (
    StatusPending    TaskStatus = "pending"     // 待执行
    StatusInProgress TaskStatus = "in_progress" // 执行中
    StatusCompleted  TaskStatus = "completed"   // 已完成
)

// 单个任务
type Task struct {
    ID          string     `json:"id"`
    Description string     `json:"description"`
    Status      TaskStatus `json:"status"`
    Dependencies []string  `json:"dependencies,omitempty"` // 依赖的任务ID
}

// 任务计划
type Plan struct {
    Goal  string `json:"goal"`  // 总目标
    Tasks []Task `json:"tasks"` // 任务列表
}
```

### 2. Plan 工具实现（来自 `generic/plan.go`）

```go
package generic

import (
    "context"
    "encoding/json"
    "sync"

    "github.com/cloudwego/eino/components/tool"
)

// Plan 管理器 - 存储和管理任务计划
type Plan struct {
    mu     sync.RWMutex
    Tasks  []Task `json:"tasks"`
    Goal   string `json:"goal"`
}

type Task struct {
    ID          string     `json:"id"`
    Description string     `json:"description"`
    Status      string     `json:"status"` // pending, in_progress, completed
    Dependencies []string   `json:"dependencies,omitempty"`
}

// create_plan 工具参数
type PlanToolInput struct {
    Goal  string `json:"goal"`
    Tasks []struct {
        Description string `json:"description"`
        DependsOn   []string `json:"depends_on,omitempty"`
    } `json:"tasks"`
}

// update_task 工具参数
type UpdateTaskInput struct {
    TaskID string `json:"task_id"`
    Status string `json:"status"` // pending, in_progress, completed
}

// CreatePlanTool - 创建任务计划的工具
func NewCreatePlanTool(plan *Plan) tool.InvokableTool {
    return &createPlanTool{plan: plan}
}

type createPlanTool struct {
    plan *Plan
}

func (t *createPlanTool) Info() *tool.SchemaInfo {
    return &tool.SchemaInfo{
        Name: "create_plan",
        Desc: `Create a task plan to accomplish a goal. 
Use this tool when you need to break down a complex task into steps.
Args: {"goal": "the main goal", "tasks": [{"description": "step description", "depends_on": []}]}`,
    }
}

func (t *createPlanTool) Run(ctx context.Context, args string) (string, error) {
    var input PlanToolInput
    if err := json.Unmarshal([]byte(args), &input); err != nil {
        return "", err
    }

    t.plan.mu.Lock()
    defer t.plan.mu.Unlock()

    t.plan.Goal = input.Goal
    t.plan.Tasks = make([]Task, 0, len(input.Tasks))

    for i, task := range input.Tasks {
        t.plan.Tasks = append(t.plan.Tasks, Task{
            ID:          fmt.Sprintf("task_%d", i+1),
            Description: task.Description,
            Status:      "pending",
            Dependencies: task.DependsOn,
        })
    }

    return fmt.Sprintf("Plan created with %d tasks:\n%s", 
        len(t.plan.Tasks), t.plan.String()), nil
}

// UpdateTaskTool - 更新任务状态的工具
func NewUpdateTaskTool(plan *Plan) tool.InvokableTool {
    return &updateTaskTool{plan: plan}
}

type updateTaskTool struct {
    plan *Plan
}

func (t *updateTaskTool) Info() *tool.SchemaInfo {
    return &tool.SchemaInfo{
        Name: "update_task",
        Desc: `Update the status of a task. 
Status can be: "pending", "in_progress", "completed".
Args: {"task_id": "task_1", "status": "completed"}`,
    }
}

func (t *updateTaskTool) Run(ctx context.Context, args string) (string, error) {
    var input UpdateTaskInput
    if err := json.Unmarshal([]byte(args), &input); err != nil {
        return "", err
    }

    t.plan.mu.Lock()
    defer t.plan.mu.Unlock()

    for i, task := range t.plan.Tasks {
        if task.ID == input.TaskID {
            t.plan.Tasks[i].Status = input.Status
            return fmt.Sprintf("Task %s updated to %s", input.TaskID, input.Status), nil
        }
    }

    return fmt.Sprintf("Task %s not found", input.TaskID), nil
}

// GetPendingTasks - 获取待执行任务
func (p *Plan) GetPendingTasks() []Task {
    p.mu.RLock()
    defer p.mu.RUnlock()

    var pending []Task
    for _, task := range p.Tasks {
        if task.Status == "pending" {
            pending = append(pending, task)
        }
    }
    return pending
}

// GetNextTask - 获取下一个可执行任务（依赖已完成）
func (p *Plan) GetNextTask() *Task {
    p.mu.RLock()
    defer p.mu.RUnlock()

    for _, task := range p.Tasks {
        if task.Status != "pending" {
            continue
        }
        // 检查依赖是否都已完成
        allDepsCompleted := true
        for _, depID := range task.Dependencies {
            for _, t := range p.Tasks {
                if t.ID == depID && t.Status != "completed" {
                    allDepsCompleted = false
                    break
                }
            }
        }
        if allDepsCompleted {
            return &task
        }
    }
    return nil
}
